def validate_token(token_string):
    """
    Validate an access token by checking the database.
    Returns the AccessToken object if valid, None otherwise.
    """
    if not token_string or not isinstance(token_string, str):
        return None

    if len(token_string) > 512:
        return None

    token_hash = AccessToken.hash_token(token_string)

    token_record = AccessToken.query.filter_by(
        token_hash=token_hash,
        is_revoked=False
    ).first()

    if token_record is None:
        return None

    if token_record.is_expired:
        return None

    if not token_record.client or not token_record.client.is_active:
        return None

    return token_record


def extract_bearer_token(request_obj):
    """Extract Bearer token from Authorization header."""
    auth_header = request_obj.headers.get('Authorization', '')

    if not auth_header:
        return None

    parts = auth_header.split(None, 1)
    if len(parts) != 2:
        return None

    scheme, token = parts
    if scheme.lower() != 'bearer':
        return None

    token = token.strip()
    if not token:
        return None

    return token


def require_oauth(*required_scopes):
    """
    Decorator to protect API endpoints with OAuth 2.0 token validation.
    Optionally checks for required scopes.

    Usage:
        @require_oauth()  # Just requires a valid token
        @require_oauth('read', 'write')  # Requires specific scopes
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token_string = extract_bearer_token(request)

            if token_string is None:
                return jsonify({
                    'error': 'unauthorized',
                    'error_description': 'Missing or invalid Authorization header. Use Bearer token.'
                }), 401, {
                    'WWW-Authenticate': 'Bearer realm="api"'
                }

            token_record = validate_token(token_string)

            if token_record is None:
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'The access token is invalid, expired, or revoked.'
                }), 401, {
                    'WWW-Authenticate': 'Bearer realm="api", error="invalid_token"'
                }

            if required_scopes:
                token_scopes = set(token_record.scope_list)
                missing_scopes = set(required_scopes) - token_scopes
                if missing_scopes:
                    return jsonify({
                        'error': 'insufficient_scope',
                        'error_description': f'Required scopes: {", ".join(required_scopes)}',
                        'missing_scopes': list(missing_scopes)
                    }), 403, {
                        'WWW-Authenticate': f'Bearer realm="api", error="insufficient_scope", scope="{" ".join(required_scopes)}"'
                    }

            g.current_token = token_record
            g.current_client = token_record.client
            g.current_user_id = token_record.user_id

            return f(*args, **kwargs)

        return decorated_function
    return decorator


