@require_oauth('admin')
def revoke_token():
    """Admin endpoint to revoke a token. Requires 'admin' scope."""
    data = request.get_json(silent=True)
    if not data or 'token' not in data:
        return jsonify({
            'error': 'bad_request',
            'error_description': 'Request must include "token" field.'
        }), 400

    target_token_string = data['token']
    if not isinstance(target_token_string, str) or len(target_token_string) > 512:
        return jsonify({
            'error': 'bad_request',
            'error_description': 'Invalid token format.'
        }), 400

    target_hash = AccessToken.hash_token(target_token_string)
    target_record = AccessToken.query.filter_by(token_hash=target_hash).first()

    if target_record is None:
        # Return success even if not found to prevent token enumeration
        return jsonify({'message': 'Token revoked successfully.'}), 200

    if not target_record.is_revoked:
        target_record.is_revoked = True

        log_entry = TokenRevocationLog(
            token_id=target_record.id,
            reason=data.get('reason', 'Admin revocation'),
            revoked_by=g.current_user_id or g.current_client.id
        )
        db.session.add(log_entry)
        db.session.commit()

    return jsonify({'message': 'Token revoked successfully.'}), 200


