@app.route('/api/v1/admin/tokens/issue', methods=['POST'])
@require_oauth('admin')
def issue_token():
    """
    Admin endpoint to issue a new access token for a client.
    In production, this would typically be handled by an authorization server.
    """
    data = request.get_json(silent=True)
    if not data:
        return jsonify({
            'error': 'bad_request',
            'error_description': 'Request body must be valid JSON.'
        }), 400

    client_id = data.get('client_id', '').strip()
    if not client_id:
        return jsonify({
            'error': 'validation_error',
            'error_description': 'client_id is required.'
        }), 422

    client = OAuthClient.query.filter_by(id=client_id, is_active=True).first()
    if client is None:
        return jsonify({
            'error': 'not_found',
            'error_description': 'Client not found or inactive.'
        }), 404

    scopes = data.get('scopes', '')
    if isinstance(scopes, list):
        # Validate each scope
        allowed_scopes = {'read', 'write', 'admin'}
        for scope in scopes:
            if scope not in allowed_scopes:
                return jsonify({
                    'error': 'validation_error',
                    'error_description': f'Invalid scope: {scope}. Allowed: {", ".join(allowed_scopes)}'
                }), 422
        scopes = ','.join(scopes)

    expires_in = data.get('expires_in', 3600)
    if not isinstance(expires_in, int) or expires_in < 60 or expires_in > 86400:
        return jsonify({
            'error': 'validation_error',
            'error_description': 'expires_in must be between 60 and 86400 seconds.'
        }), 422

    user_id = data.get('user_id')
    if user_id is not None:
        user_id = str(user_id).strip()[:128]

    raw_token = secrets.token_urlsafe(48)

    token_record = AccessToken(
        token_hash=AccessToken.hash_token(raw_token),
        client_id=client_id,
        scopes=scopes,
        expires_at=datetime.now(timezone.utc) + timedelta(seconds=expires_in),
        user_id=user_id
    )

    db.session.add(token_record)
    db.session.commit()

    return jsonify({
        'access_token': raw_token,
        'token_type': 'Bearer',
        'expires_in': expires_in,
        'scopes': token_record.scope_list,
        'message': 'Store the access_token securely.'
    }), 201


